var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"네바다주 제 16 이터니움 반응로 실험기지     \\n<color=#ffd34c>델타세븐</color> 카일 웡","JPN":"ネバダ州、第16エタニウム反応炉の実験基地     \\n<color=#ffd34c>デルタセブン</color> カイル・ウォン","ENG":"[[","TWN":"內華達州第16永恆之金反應爐實驗基地  \\n<color=#ffd34c>第七三角洲部隊</color> 凱爾","THA":"ปฏิกรณ์อีเทอร์เนียมเนวาดา พื้นที่ทดสอบ 16 \\n<color=#ffd34c>เดลต้าเซเว่น</color> ไคล์ หว่อง","VTN":"Khu Vực Thử Nghiệm Lò Phản Ứng Vàng Vĩnh Cửu Nevada 16    \\n<color=#ffd34c>Delta Seven</color> Kyle Wong","SCN":"内华达州第16能晶反应炉实验基地  \\n<color=#ffd34c>德尔塔部队</color> 凯尔","DEU":"Nevada, Eterniumreaktor, Testbereich\xA016    \\n<color=#ffd34c>Delta Seven</color> Kyle Wong","FRA":"Zone de test n°16 du réacteur à éternium, Nevada\\nKyle\xA0Wong,<color=#ffd34c>Delta\xA0Seven</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"준비상황은 어떻습니까?","JPN":"準備はいかがですか？","ENG":"How's your preparation going?","TWN":"準備得怎麼樣了？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"방금 주 전원 연결을 마쳤습니다. 이제 연료용 액화 이터니움을 충전하면 실험 준비는 끝입니다.","JPN":"ちょうど電源接続を終えたところです。\\nこの後、燃料用の液状エタニウムを充填すれば、実験準備は完了します。","ENG":"We've just connected the main power. Once we fill it with liquid Eternium fuel, we'll be ready for the experiment.","TWN":"剛剛已經連接上了主電源。現在只要注入液化永恆之金作為燃料，實驗準備就結束了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"성공 확률은 어느 정도라고 예상하십니까?","JPN":"成功する確率はどのくらいでしょう？","ENG":"What do you think our chance of success is?","TWN":"你預計成功率大概有多少？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"마음 같아선 100%라고 말씀드리고 싶지만......","JPN":"100％と言いたいところですが……","ENG":"I want to say 100%, but...","TWN":"雖然我很想說是100%……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"아시다시피, 이터니움 드라이브의 핵심기술은 관리국 놈들이 독점하고 있습니다. 역설계도 한계가 있죠.","JPN":"ご存知の通り、エタニウムドライブの核心となる技術は管理局の奴らが独占しているので。\\nリバースエンジニアリングにも限界がありますからね。","ENG":"As you know, the Administration monopolizes the core technology of Eternium drives, and there's only so much we can figure out through reverse-engineering.","TWN":"但您也知道，永恆之金引擎的核心技術一直被管理局那群傢伙獨佔著。逆向工程是有極限的。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"하지만 언제까지 관리국이 던져 주는 뼈다귀만 받아 먹어서야 되겠습니까?","JPN":"ですが、いつまでも管理局頼みではいられません。","ENG":"But it's time we stop relying on the bones that the Administration throws our way after it feasts on them.","TWN":"但我們得啃管理局吃剩的骨頭到什麼時候？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"우리 공군 기술 연구소도, 기술력이라면 세계 최고를 자부하고 있습니다.","JPN":"我が空軍技術研究所も、技術力では世界最高レベルを自負していますから。","ENG":"Our Air Force tech lab is next to none when it comes to technological power.","TWN":"我們空軍技術研究所的技術力，絕對算得上世界第一。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"이번 시험 기동에 성공한다면, 기존의 함선급 이터니움 드라이브를 능가하는 고출력 엔진을 만들 수 있을 겁니다.","JPN":"今回の試運転に成功したら、従来の艦船級のエタニウムドライブをしのぐ、\\n高出力エンジンを作ることができるでしょう。","ENG":"If we succeed in this test activation, we should be able to produce a high-powered engine that outshines any existing ship-grade Eternium drive.","TWN":"如果這次實驗成功，就可以研發出超過所有艦船級的高功率永恆之金引擎。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말씀대로 되길 바라겠습니다.","JPN":"おっしゃるとおりに実現できるといいですね。","ENG":"I hope so.","TWN":"希望能如你所說。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"언제까지 이터니움 드라이브를 빌미로 국방력에 제약을 받을 수는 없으니까요.","JPN":"いつまでもエタニウムドライブが国防力の足かせになるのは望ましくないですからね。","ENG":"We can't let Eternium drives be a weakness in our national defense anymore.","TWN":"畢竟我們不能一直因為永恆之金引擎的事情受到國防勢力的限制。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"반응로 내 이터니움 충전 완료! 기동 대기 중!","JPN":"反応炉内のエタニウム充填完了！　起動待機中！","ENG":"The reactor has been filled with Eternium. It's ready for activation.","TWN":"永恆之金充能完畢！待機中！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"반응로 점화 카운트다운, 시작하겠습니다.","JPN":"反応炉点火のカウントダウンを開始します。","ENG":"Starting the countdown to reactor ignition...","TWN":"反應爐點火倒數計時開始。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"3, 2, 1......","JPN":"3、2、1……","ENG":"3, 2, 1......","TWN":"3， 2， 1……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"반응로, 점화!","JPN":"反応炉、点火！","ENG":"Ignite the reactor!","TWN":"反應爐，點火！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_NULL","text":{"KOREA":"출력 순조롭게 상승 중! 에너지 시그니처는 안정적인 상태입니다!","JPN":"出力、順調に上昇中！　エネルギーシグネチャーは安定しています！","ENG":"Output is rising smoothly. Energy signature is stable.","TWN":"輸出穩定上升中！能量狀態穩定！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};